proof fn phi_1_equiv_reflexive_fold_equal<A, B>(s: Seq<A>, eq: spec_fn(A, A) -> bool, init: B, f: spec_fn(B, A) -> B)
    requires
        forall |a1: A, a2: A| eq(a1, a2) ==> f(init, a1) == f(init, a2),
        forall |b: B, a1: A, a2: A| eq(a1, a2) ==> #[trigger] f(b, a1) == #[trigger] f(b, a2),
        forall |i: int| 0 <= i < s.len() ==> eq(s[i], s[i]),
    ensures
        s.fold_left(init, f) == s.fold_left(init, f),
{
    lemma_fold_left_on_equiv_seqs(s, s, eq, init, f);
}

proof fn phi_2_empty_seqs_any_eq<A, B>(init: B, f: spec_fn(B, A) -> B, eq: spec_fn(A, A) -> bool)
    requires
        forall |b: B, a1: A, a2: A| eq(a1, a2) ==> #[trigger] f(b, a1) == #[trigger] f(b, a2),
    ensures
        Seq::<A>::empty().fold_left(init, f) == Seq::<A>::empty().fold_left(init, f),
{
    lemma_fold_left_on_equiv_seqs(Seq::<A>::empty(), Seq::<A>::empty(), eq, init, f);
}

proof fn phi_4_congruence_only_on_eq_not_f_output<A>(s1: Seq<A>, s2: Seq<A>, eq: spec_fn(A, A) -> bool, init: int, f: spec_fn(int, A) -> int)
    requires
        s1.len() == s2.len(),
        forall |i: int| 0 <= i < s1.len() ==> eq(s1[i], s2[i]),
        forall |b: int, a1: A, a2: A| eq(a1, a2) ==> #[trigger] f(b, a1) == #[trigger] f(b, a2),
    ensures
        s1.fold_left(init, f) == s2.fold_left(init, f),
{
    lemma_fold_left_on_equiv_seqs(s1, s2, eq, init, f);
}

proof fn phi_5_constant_f_any_seqs_equal_fold(s1: Seq<int>, s2: Seq<int>, init: int)
    requires
        s1.len() == s2.len(),
    ensures
        s1.fold_left(init, |b: int, _a: int| b) == s2.fold_left(init, |b: int, _a: int| b),
{
    let eq = |_a1: int, _a2: int| true;
    let f = |b: int, _a: int| b;
    lemma_fold_left_on_equiv_seqs(s1, s2, eq, init, f);
}
